 1→/**
 2→ * Walk a Lexical JSON tree and collect unique mentionUserId values.
 3→ * Returns an array of user ID strings.
 4→ */
 5→export function extractMentionUserIds(contentJson) {
 6→    const ids = new Set();
 7→
 8→    let parsed;
 9→    try {
10→        parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
11→    } catch {
12→        return [];
13→    }
14→
15→    function walk(node) {
16→        if (!node) return;
17→        if (node.type === 'mention' && node.mentionUserId) {
18→            ids.add(node.mentionUserId);
19→        }
20→        if (Array.isArray(node.children)) {
21→            for (const child of node.children) {
22→                walk(child);
23→            }
24→        }
25→    }
26→
27→    walk(parsed?.root ?? parsed);
28→    return [...ids];
29→}
