223→export const uploadJournalContentService = async(
224→    content,
225→    title,
226→    userId,
227→    remixSourceJournalId = null,
228→    isRemix = false,
229→    promptId = null
230→) =>{
231→    if(!userId){
232→        console.error('userId is undefined');
233→        throw {status: 400, error: 'userId is undefined'};
234→    }
235→
236→    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
237→
238→    if(!trimmedTitle){
239→        console.error('title is missing!');
240→        throw {status: 400, error: 'title is missing!'};
241→    }
242→
243→    const shouldSaveRemixMetadata = Boolean(
244→        remixSourceJournalId
245→        && typeof remixSourceJournalId === 'string'
246→        && remixSourceJournalId.trim()
247→    );
248→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
249→
250→    if(!content){
251→        console.error('content is missing for text post!');
252→        throw {status: 400, error: 'content is missing for text post'};
253→    }
254→
255→    const parseData = parseTextContentSafely(content);
256→    if(!parseData){
257→        console.error('error while parsing text content data');
258→        throw {status: 400, error: 'error while parsing text content data'};
259→    }
260→
261→    const embeddingBody = parseData.wholeText || '';
262→    const payload = {
263→        user_id: userId,
264→        title: trimmedTitle,
265→        post_type: POST_TYPE_TEXT,
266→        content: content,
267→    };
268→
269→    const embeddingResult = await GenerateEmbeddings(trimmedTitle, embeddingBody);
270→
271→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
272→        console.error('error while generating embeddings on a post!');
273→        throw {status: 400, error: 'error while generating embeddings on a post!'};
274→    }
275→
276→    const insertPayload = {
277→        ...payload,
278→        embeddings: embeddingResult
279→    };
280→
281→    if(normalizedIsRemix){
282→        insertPayload.is_remix = true;
283→    }
284→    if(shouldSaveRemixMetadata){
285→        insertPayload.remix_source_journal_id = remixSourceJournalId.trim();
286→    }
287→    if(promptId){
288→        const parsedPromptId = parseInt(promptId, 10);
289→        if(!isNaN(parsedPromptId)){
290→            insertPayload.prompt_id = parsedPromptId;
291→        }
292→    }
293→
294→    let insertResult = await supabase
295→    .from('journals')
296→    .insert(insertPayload)
297→    .select('id')
298→    .single();
299→
300→    let error = insertResult.error;
301→
302→    if(error){
303→        const missingRemixColumns = error?.message?.includes('is_remix') || error?.message?.includes('remix_source_journal_id');
304→        if(missingRemixColumns){
305→            const fallbackPayload = {
306→                ...payload,
307→                embeddings: embeddingResult
308→            };
309→
310→            insertResult = await supabase
311→            .from('journals')
312→            .insert(fallbackPayload)
313→            .select('id')
314→            .single();
315→            error = insertResult.error;
316→        }
317→    }
318→
319→    if(error){
320→        console.error('supabase error while uploading content:',error.message);
321→        throw {status: 500, error: 'supabase error while uploading content'};
322→    }
323→
324→    const journalId = insertResult.data?.id;
325→
326→    // Non-fatal: send mention notifications
327→    if(journalId){
328→        try {
329→            const mentionedUserIds = extractMentionUserIds(content);
330→            const filtered = mentionedUserIds
331→                .filter(id => id !== userId)
332→                .slice(0, 50);
333→
334→            if(filtered.length > 0){
335→                const notifRows = filtered.map(receiverId => ({
336→                    sender_id: userId,
337→                    receiver_id: receiverId,
338→                    type: 'mention',
339→                    journal_id: journalId,
340→                    read: false
341→                }));
342→
343→                const {error: notifError} = await supabase
344→                    .from('notifications')
345→                    .insert(notifRows);
346→
347→                if(notifError){
348→                    console.error('non-fatal: mention notification insert failed:', notifError.message);
349→                }
350→            }
351→        } catch (mentionErr) {
352→            console.error('non-fatal: mention extraction failed:', mentionErr?.message || mentionErr);
353→        }
354→    }
355→
356→    // Non-fatal: record publish for writing streak
357→    let streakResult = null;
358→    try {
359→        const { recordPublishForStreak } = await import('./streakService.js');
