 31→const extractBearerToken = (authHeader = "") => {
 32→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
 33→    if (!trimmed) return "";
 34→
 35→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
 36→    if (bearerMatch?.[1]) {
 37→        return bearerMatch[1].trim();
 38→    }
 39→
 40→    return trimmed;
 41→};
